/**
 * Seed MongoDB with all pet data + jsDelivr CDN image URLs.
 * Usage: MONGODB_URI=... node src/seed.js
 */
require("dotenv").config();
const mongoose = require("mongoose");
const Pet = require("./models/Pet");

const CDN = "https://cdn.jsdelivr.net/gh/llcoolj0303/pet-fighters-assets@main/cropped";

function safeName(name) {
  return name.replace(/[^a-zA-Z0-9_\-]/g, "_");
}

function imageUrl(id, name) {
  return `${CDN}/${id}_${safeName(name)}.png`;
}

function hoverUrl(id, name) {
  return `${CDN}/${id}_${safeName(name)}_hover.png`;
}

