async function seed() {
  await mongoose.connect(process.env.MONGODB_URI);
  console.log("Connected to MongoDB");

  await Pet.deleteMany({});
  console.log("Cleared existing pets");

  const docs = PETS.map((p) => ({
    ...p,
    imageUrl:      imageUrl(p.id, p.name),
    hoverImageUrl: hoverUrl(p.id, p.name),
  }));

  await Pet.insertMany(docs);
  console.log(`Seeded ${docs.length} pets`);

  await mongoose.disconnect();
  console.log("Done!");
}

seed().catch((err) => {
  console.error(err);
  process.exit(1);
});
